#include <stdio.h>
#include <stdbool.h>
#define MAX_R 6
#define MAX_C 6

bool exist(char grid[MAX_R][MAX_C], int r, int c, char *s, int len, int index, bool visited[MAX_R][MAX_C]) {
    if (index == len) return true;
    if (r < 0 || r >= MAX_R || c < 0 || c >= MAX_C || visited[r][c] || grid[r][c] != s[index]) return false;
    visited[r][c] = true;
    bool found = exist(grid, r-1, c, s, len, index+1, visited) ||
                   exist(grid, r+1, c, s, len, index+1, visited) ||
                   exist(grid, r, c-1, s, len, index+1, visited) ||
                   exist(grid, r, c+1, s, len, index+1, visited);
    visited[r][c] = false;
    return found;
}

int main() {
    int r, c;
    scanf("%d %d", &r, &c);
    char grid[MAX_R][MAX_C];
    for (int i = 0; i < r; i++) {
        for (int j = 0; j < c; j++) {
            scanf(" %c", &grid[i][j]);
        }
    }
    char s[100];
    scanf("%s", s);
    int len = strlen(s);
    bool found = false;
    bool visited[MAX_R][MAX_C] = {{false}};
    for (int i = 0; i < r; i++) {
        for (int j = 0; j < c; j++) {
            if (exist(grid, i, j, s, len, 0, visited)) {
                found = true;
                break;
            }
        }
        if (found) break;
    }
    printf("%s\n", found ? "true" : "false");
    return 0;
}

