bool exist(vector<vector<char>>& grid, int r, int c, string& s, int index, vector<vector<bool>>& visited) {
    if (index == s.size()) return true;
    if (r < 0 || r >= grid.size() || c < 0 || c >= grid[0].size() || visited[r][c] || grid[r][c] != s[index]) return false;
    visited[r][c] = true;
    bool found = exist(grid, r-1, c, s, index+1, visited) ||
                   exist(grid, r+1, c, s, index+1, visited) ||
                   exist(grid, r, c-1, s, index+1, visited) ||
                   exist(grid, r, c+1, s, index+1, visited);
    visited[r][c] = false;
    return found;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    int r, c;
    cin >> r >> c;
    vector<vector<char>> grid(r, vector<char>(c));
    for (int i = 0; i < r; i++) {
        for (int j = 0; j < c; j++) {
            cin >> grid[i][j];
        }
