import java.util.Scanner;
public class Main {
    public static boolean exist(char[][] grid, int r, int c, String s, int index, boolean[][] visited) {
        if (index == s.length()) return true;
        if (r < 0 || r >= grid.length || c < 0 || c >= grid[0].length || visited[r][c] || grid[r][c] != s.charAt(index)) return false;
        visited[r][c] = true;
        boolean found = exist(grid, r-1, c, s, index+1, visited) ||
                           exist(grid, r+1, c, s, index+1, visited) ||
                           exist(grid, r, c-1, s, index+1, visited) ||
                           exist(grid, r, c+1, s, index+1, visited);
        visited[r][c] = false;
        return found;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int r = scanner.nextInt();
        int c = scanner.nextInt();
        char[][] grid = new char[r][c];
        for (int i = 0; i < r; i++) {
            for (int j = 0; j < c; j++) {
                grid[i][j] = scanner.next().charAt(0);
            }
        }
        String s = scanner.next();
        boolean found = false;
        boolean[][] visited = new boolean[r][c];
        for (int i = 0; i < r; i++) {
            for (int j = 0; j < c; j++) {
                if (exist(grid, i, j, s, 0, visited)) {
                    found = true;
                    break;
                }
            }
            if (found) break;
        }
        System.out.println(found ? "true" : "false");
    }
}

